const { status, order_number, tracking_number, customer_psid } = $input.item.json;
const messages = {
  received:          `รับหมวกของคุณแล้วครับ (Order: ${order_number}) 📦`,
  in_progress:       `เริ่มดำเนินการแล้วครับ กำลังจัดทรง/ซัก 🧢`,
  completed:         `งานเสร็จแล้วครับ! รอยืนยันชำระเงินนะครับ ✅`,
  shipped:           `ส่งหมวกกลับแล้วครับ เลขพัสดุ: ${tracking_number} 🚚`,
};
return [{ json: { psid: customer_psid, message: messages[status] || `อัปเดตสถานะ: ${status}` } }];
